<template>
  <form ref="paymentForm" :action="gatewayUrl" method="POST">
    <input
      v-for="(v, k) in formData"
      :key="k"
      :name="k"
      :value="v"
    />
  </form>
</template>

<script>
import DataService from '../../services/DataService';
export default {

    data() {
    return {
      gatewayUrl: "",
      formData: {}
    };
  },

 created:function(){
  debugger
  console.log('this.formData');
   this.callpaymentgateway()  
 },
methods:{
    async callpaymentgateway() {
    debugger
      var obj=
          {
            gateway: 'PayFast',//'paypro',//'PayFast',//'JazzCash',
            amount: 1000,
            orderId: 'ORD-1001',
            description: 'Sandbox test payment'
          };
            var data=JSON.stringify(obj);
          await DataService.Initiate(data).then((response)=>{;
      debugger
          this.gatewayUrl = response.data.redirectUrl;
          this.formData = response.data.formData;
          console.log('response',response);
          console.log('this.formData',this.formData);
          console.log('this.gatewayUrl',this.redirectUrl);

            this.$nextTick(() => {
              debugger
              console.log(this.$refs.paymentForm);
              this.$refs.paymentForm.submit(); // 🔥 opens gateway UI
            });
        });
        },
}
};

</script>
